import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import 'bootstrap/dist/css/bootstrap.min.css';

const dummyProducts = [
  { id: 1, name: 'Apples', price: 20.99, image: 'data:image/jpeg;base64,', },
  { id: 2, name: 'Bananas', price: 30.99, image: 'data:image/jpeg;base64,', },
  { id: 3, name: 'Milk', price: 70.49, image: 'data:image/jpeg;base64,', },
  { id: 4, name: 'Bread', price: 35.49, image: 'data:image/jpeg;base64,' },
  { id: 5, name: 'Eggs', price: 27.99, image: 'data:image/jpeg;base64,', },
  { id: 6, name: 'Cheese', price: 110.99, image: 'data:image/jpeg;base64,', },
  { id: 7, name: 'Carrots', price: 30.29, image: 'data:image/jpeg;base64,', },
];

const Products = () => {
  const [cart, setCart] = useState([]);
  const navigate = useNavigate();

  const addToCart = (product) => {
    const currentCart = JSON.parse(localStorage.getItem('cart')) || [];
    currentCart.push(product);
    localStorage.setItem('cart', JSON.stringify(currentCart));
    setCart(currentCart);
    navigate('/cart');
    alert(`${product.name} added to cart`);
  };

  return (
    
    <div className="container py-5">
        {/* 🟢 Added Back to Home Button */}
      <div className="mb-3">
        <button className="btn btn-outline-secondary" onClick={() => navigate('/')}>
          ⬅ Back to Home
        </button>
      </div>
      <h2 className="text-center text-success mb-4">🛍️ All Products</h2>
      <div className="row g-4">
        {dummyProducts.map((product) => (
          <div className="col-12 col-sm-6 col-md-4 col-lg-3" key={product.id}>
            <div className="card h-100 shadow-sm">
              <img
                src={product.image}
                alt={product.name}
                className="card-img-top img-fluid"
                style={{ objectFit: 'cover', height: '150px' }}
              />
              <div className="card-body d-flex flex-column">
                <h5 className="card-title">{product.name}</h5>
                <p className="card-text text-muted">₹{product.price}</p>
                <div className="mt-auto d-grid gap-2">
                  <button
                    className="btn btn-outline-primary"
                    onClick={() => navigate('/fresh-deals')}
                  >
                    Fresh Deals
                  </button>
                  <button
                    className="btn btn-success"
                    onClick={() => addToCart(product)}
                  >
                    Add to Cart
                  </button>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Products;
